const html = $input.first().json.data || $input.first().json;
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

// Hilfsfunktion: deutsche Zahlen parsen (8.050 → 8050)
const parseDE = str => parseInt(str.replace(/\./g, '').replace(/,/g, '.'), 10);

// Fans
const fansMatch = htmlStr.match(/(\d[\d.]*?)\s*Fans/);
const fans = fansMatch ? parseDE(fansMatch[1]) : null;

// Profilbesucher
const besucherMatch = htmlStr.match(/(\d[\d.]*?)\s*Besucher/);
const besucher = besucherMatch ? parseDE(besucherMatch[1]) : null;

// Bewertungen
const bewMatch = htmlStr.match(/(\d+)\s*Bewertungen/);
const bewertungen = bewMatch ? parseInt(bewMatch[1], 10) : null;

// Rating
const ratingMatch = htmlStr.match(/([\d,]+)\s*von\s*5/);
const rating = ratingMatch ? parseFloat(ratingMatch[1].replace(',', '.')) : null;

return [{ json: { fans, besucher, bewertungen, rating, updatedAt: new Date().toISOString() } }];
